-- ============================================================
-- Online Learning Platform - Seed Data
-- 50 Instructors + 500 Students + 30 Courses + Lessons + More
-- Default password for ALL users: password123
-- ============================================================

USE auth_db;

-- Wait for Hibernate to create tables, so we use CREATE TABLE IF NOT EXISTS
CREATE TABLE IF NOT EXISTS users (
  user_id BIGINT AUTO_INCREMENT PRIMARY KEY,
  username VARCHAR(255) UNIQUE NOT NULL,
  email VARCHAR(255) UNIQUE NOT NULL,
  password_hash VARCHAR(255) NOT NULL,
  role VARCHAR(20) NOT NULL,
  is_active BOOLEAN DEFAULT TRUE,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);


USE instructor_db;

CREATE TABLE IF NOT EXISTS instructors (
  instructor_id BIGINT PRIMARY KEY,
  first_name VARCHAR(255), last_name VARCHAR(255), email VARCHAR(255),
  bio TEXT, expertise VARCHAR(255), profile_picture VARCHAR(500),
  linkedin_profile VARCHAR(500), website_url VARCHAR(500),
  total_courses INT DEFAULT 0, total_students INT DEFAULT 0,
  rating DOUBLE DEFAULT 0.0, is_verified BOOLEAN DEFAULT FALSE,
  joined_at DATETIME DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS instructor_reviews (
  review_id BIGINT AUTO_INCREMENT PRIMARY KEY,
  instructor_id BIGINT, student_id BIGINT,
  rating INT, comment TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);



USE student_db;

CREATE TABLE IF NOT EXISTS students (
  student_id BIGINT PRIMARY KEY,
  first_name VARCHAR(255), last_name VARCHAR(255), email VARCHAR(255),
  date_of_birth DATE, phone_number VARCHAR(20),
  profile_picture VARCHAR(500), bio TEXT,
  registered_at DATETIME DEFAULT CURRENT_TIMESTAMP, is_active BOOLEAN DEFAULT TRUE
);

CREATE TABLE IF NOT EXISTS student_progress (
  progress_id BIGINT AUTO_INCREMENT PRIMARY KEY,
  student_id BIGINT, course_id BIGINT,
  completed_lessons INT DEFAULT 0, total_lessons INT DEFAULT 0,
  progress_percent DOUBLE DEFAULT 0.0,
  last_accessed_at DATETIME, is_completed BOOLEAN DEFAULT FALSE
);






USE course_db;

CREATE TABLE IF NOT EXISTS course_categories (
  category_id BIGINT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(255) UNIQUE, description TEXT, icon_url VARCHAR(500)
);

CREATE TABLE IF NOT EXISTS courses (
  course_id BIGINT AUTO_INCREMENT PRIMARY KEY,
  title VARCHAR(255), description TEXT, instructor_id BIGINT,
  category_category_id BIGINT, thumbnail_url VARCHAR(500),
  price DOUBLE DEFAULT 0.0, level VARCHAR(20), language VARCHAR(50),
  is_published BOOLEAN DEFAULT TRUE, total_lessons INT DEFAULT 0,
  created_at DATETIME, updated_at DATETIME,
  FOREIGN KEY (category_category_id) REFERENCES course_categories(category_id)
);

CREATE TABLE IF NOT EXISTS lessons (
  lesson_id BIGINT AUTO_INCREMENT PRIMARY KEY,
  course_id BIGINT, title VARCHAR(255), content TEXT,
  video_url VARCHAR(500), duration INT,
  order_index INT, is_preview BOOLEAN DEFAULT FALSE,
  FOREIGN KEY (course_id) REFERENCES courses(course_id)
);












USE enrollment_db;

CREATE TABLE IF NOT EXISTS enrollments (
  enrollment_id BIGINT AUTO_INCREMENT PRIMARY KEY,
  student_id BIGINT, course_id BIGINT,
  enrolled_at DATETIME, status VARCHAR(20) DEFAULT 'ACTIVE',
  completed_at DATETIME, payment_id VARCHAR(255), amount_paid DOUBLE DEFAULT 0.0
);

CREATE TABLE IF NOT EXISTS wish_lists (
  wishlist_id BIGINT AUTO_INCREMENT PRIMARY KEY,
  student_id BIGINT, course_id BIGINT,
  added_at DATETIME DEFAULT CURRENT_TIMESTAMP
);









USE student_db;








USE quiz_db;

CREATE TABLE IF NOT EXISTS quizzes (
  quiz_id BIGINT AUTO_INCREMENT PRIMARY KEY,
  course_id BIGINT, title VARCHAR(255), description TEXT,
  total_marks INT, passing_marks INT, time_limit INT, is_active BOOLEAN DEFAULT TRUE
);

CREATE TABLE IF NOT EXISTS questions (
  question_id BIGINT AUTO_INCREMENT PRIMARY KEY,
  quiz_id BIGINT, question_text TEXT,
  option_a VARCHAR(500), option_b VARCHAR(500), option_c VARCHAR(500), option_d VARCHAR(500),
  correct_option VARCHAR(5), marks INT, order_index INT
);

CREATE TABLE IF NOT EXISTS quiz_attempts (
  attempt_id BIGINT AUTO_INCREMENT PRIMARY KEY,
  quiz_id BIGINT, student_id BIGINT,
  started_at DATETIME, submitted_at DATETIME,
  score INT, is_passed BOOLEAN, attempt_number INT
);





USE certificate_db;

CREATE TABLE IF NOT EXISTS certificates (
  certificate_id BIGINT AUTO_INCREMENT PRIMARY KEY,
  certificate_code VARCHAR(255) UNIQUE, student_id BIGINT, course_id BIGINT,
  instructor_id BIGINT, student_name VARCHAR(500), course_name VARCHAR(500),
  issued_at DATETIME, certificate_url VARCHAR(500), is_valid BOOLEAN DEFAULT TRUE
);



-- ============================================================
-- Seed data complete!
